/**
 * MajuRun — Seed Firestore with Sample Posts
 *
 * Reads asset_urls.json generated by upload_to_cloudinary.js,
 * then creates realistic seed posts in Firestore so the
 * social feed looks active for new users.
 *
 * SETUP:
 *   1. npm install firebase-admin dotenv
 *   2. Download Firebase service account key:
 *      Firebase Console → Project Settings → Service Accounts → Generate new private key
 *      Save as: scripts/firebase_service_account.json
 *   3. Run: node scripts/seed_firestore.js
 *
 * SAFE TO RE-RUN: checks for existing seed posts before inserting.
 */

const admin = require('firebase-admin');
const path  = require('path');
const fs    = require('fs');
require('dotenv').config({ path: path.join(__dirname, '.env') });

// ─── INIT FIREBASE ────────────────────────────────────────────────────────────

const serviceAccountPath = path.join(__dirname, 'firebase_service_account.json');
if (!fs.existsSync(serviceAccountPath)) {
  console.error('❌ Missing firebase_service_account.json');
  console.error('   Download from: Firebase Console → Project Settings → Service Accounts');
  process.exit(1);
}

admin.initializeApp({
  credential: admin.credential.cert(require(serviceAccountPath)),
});

const db = admin.firestore();

// ─── LOAD ASSET URLS ─────────────────────────────────────────────────────────

const urlsPath = path.join(__dirname, 'output', 'asset_urls.json');
let assetUrls = {};
if (fs.existsSync(urlsPath)) {
  assetUrls = JSON.parse(fs.readFileSync(urlsPath, 'utf8'));
  console.log(`📦 Loaded ${Object.keys(assetUrls).length} asset URLs`);
} else {
  console.warn('⚠️  No asset_urls.json found — using placeholder URLs');
  console.warn('   Run upload_to_cloudinary.js first for real URLs');
}

function getUrl(key) {
  return assetUrls[key] || `https://placeholder.com/${key}`;
}

// ─── SEED POST DEFINITIONS ───────────────────────────────────────────────────

// Spread posts over past 30 days so feed looks organic
function daysAgo(n) {
  const d = new Date();
  d.setDate(d.getDate() - n);
  return admin.firestore.Timestamp.fromDate(d);
}

