// ─── MAIN ────────────────────────────────────────────────────────────────────

async function main() {
  console.log('🌱 MajuRun Firestore Seeder\n');

  // Check if seed posts already exist
  const existing = await db.collection('posts')
    .where('userId', '==', 'seed_account')
    .limit(1)
    .get();

  if (!existing.empty) {
    console.log('⚠️  Seed posts already exist in Firestore.');
    console.log('   Delete existing seed posts first or run with --force flag.');
    const force = process.argv.includes('--force');
    if (!force) {
      console.log('\n   To re-seed: node scripts/seed_firestore.js --force');
      process.exit(0);
    }
    console.log('   --force flag detected, deleting existing seed posts...\n');
    const allSeed = await db.collection('posts').where('userId', '==', 'seed_account').get();
    const batch = db.batch();
    allSeed.docs.forEach(doc => batch.delete(doc.ref));
    await batch.commit();
    console.log(`   Deleted ${allSeed.size} existing seed posts\n`);
  }

  console.log(`📝 Creating ${SEED_POSTS.length} seed posts...\n`);

  const batch = db.batch();
  let count = 0;

  for (const post of SEED_POSTS) {
    const ref = db.collection('posts').doc();
    batch.set(ref, {
      userId: 'seed_account',
      username: 'MajuRun Community',
      userAvatar: getUrl('mascot/mascot_running.png'),
      type: 'seed_post',
      isSeed: true,
      content: post.content,
      mapImageUrl: post.mapImageUrl,
      distance: post.distance ?? null,
      pace: post.pace ?? null,
      bpm: post.bpm ?? null,
      planTitle: post.planTitle ?? null,
      likes: [],
      likeCount: post.likeCount,
      commentCount: post.commentCount,
      tags: post.tags ?? [],
      createdAt: post.createdAt,
    });
    console.log(`  ✅ "${post.content.substring(0, 50)}..."`);
    count++;
  }

  await batch.commit();

  console.log(`\n─────────────────────────────────`);
  console.log(`✅ Created ${count} seed posts in Firestore`);
  console.log(`─────────────────────────────────`);
  console.log('\n✨ Done! Open the app and check the social feed.');
  process.exit(0);
}

main().catch(err => {
  console.error('💥 Fatal error:', err);
  process.exit(1);
});
